param([string]$To="kwilliamkatul@vectarr.com",[string]$From="asferrazza@vectarr.com",[string]$Subject="Test Email from Alexander Sferrazza")
try{$s=Get-Content "$env:APPDATA\Microsoft\Signatures\Vectarr (asferrazza@vectarr.com).htm"-Raw;$o=New-Object -ComObject Outlook.Application;$m=$o.CreateItem(0);$m.To=$To;$m.Subject=$Subject;$Body="Hi Kamal,<br><br>This is a test email from asferrazza@vectarr.com using the correct signature.<br><br>Please confirm you received this and the signature displays correctly.<br><br>Best regards,";$m.HTMLBody="<!DOCTYPE html><html><head><meta charset='UTF-8'></head><body style='font-family:Arial,sans-serif;'><p>$Body</p><br>$s</body></html>";$a=$o.Session.Accounts|Where-Object{$_.SmtpAddress-eq$From};if($a){$m.SendUsingAccount=$a;Write-Host "Test email sent from $From to $To"}else{Write-Warning "Account not found";exit 1};$m.Send()}catch{Write-Error "Failed: $_";exit 1}finally{if($m){[System.Runtime.Interopservices.Marshal]::ReleaseComObject($m)|Out-Null}if($o){[System.Runtime.Interopservices.Marshal]::ReleaseComObject($o)|Out-Null}}